import { AuthState } from './auth/auth.reducer';
import { ProductsState } from './products/products.reducer';

export interface AppState {
  auth: AuthState;
  products: ProductsState;
}

import { Inject, Injectable, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

export interface AppUser {
  sub:     string;
  name:    string;
  email:   string;
  picture: string;
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly tokenKey = 'auth_token';
  private readonly userKey  = 'auth_user';

  user:  AppUser | null = null;
  token: string | null  = null;

  constructor(@Inject(PLATFORM_ID) private platformId: object) {}

  async restoreSession(): Promise<void> {
    if (!isPlatformBrowser(this.platformId)) {
      console.log('[AuthService] Skipped — not browser (SSR)');
      return;
    }

    const storedToken   = sessionStorage.getItem(this.tokenKey);
    const storedUserRaw = sessionStorage.getItem(this.userKey);

    console.log('[AuthService] storedUserRaw:', storedUserRaw);
    console.log('[AuthService] storedToken:', storedToken);

    if (!storedUserRaw) { this.clear(); return; }

    try {
      this.user  = JSON.parse(storedUserRaw);
      this.token = storedToken ?? null;
    } catch { this.clear(); }
  }

  async signInWithGoogle(credential: string): Promise<void> {
    const payload = this.parseJwt(credential);
    this.token = credential;
    this.user  = {
      sub:     payload.sub,
      name:    payload.name,
      email:   payload.email,
      picture: payload.picture,
    };
    if (isPlatformBrowser(this.platformId)) {
      sessionStorage.setItem(this.tokenKey, credential);
      sessionStorage.setItem(this.userKey,  JSON.stringify(this.user));
    }
  }

  async signInWithEmail(user: AppUser): Promise<void> {
    this.token = null;
    this.user  = user;
    if (isPlatformBrowser(this.platformId)) {
      sessionStorage.removeItem(this.tokenKey);
      sessionStorage.setItem(this.userKey, JSON.stringify(user));
    }
  }

  async logout(): Promise<void> { this.clear(); }

  private clear(): void {
    this.token = null;
    this.user  = null;
    if (isPlatformBrowser(this.platformId)) {
      sessionStorage.removeItem(this.tokenKey);
      sessionStorage.removeItem(this.userKey);
    }
  }

  parseJwt(token: string): any {
    const parts  = token.split('.');
    if (parts.length < 2) throw new Error('Invalid JWT');
    const base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    const padded = base64 + '='.repeat((4 - (base64.length % 4)) % 4);
    return JSON.parse(atob(padded));
  }
}

import { createFeature, createReducer, on } from '@ngrx/store';
import { AppUser } from '../../core/auth/services/auth-service';
import { AuthActions } from './auth.actions';

export interface AuthState {
  user:    AppUser | null;
  token:   string | null;
  loading: boolean;
  error:   string | null;
  sessionRestored:  boolean;
}

const initialState: AuthState = {
  user: null, token: null, loading: false, error: null,
  sessionRestored:  false,
};

export const authFeature = createFeature({
  name: 'auth',
  reducer: createReducer(
    initialState,
    on(AuthActions.restoreSessionSuccess,
      (s, { user, token }) => ({ ...s, user, token, loading: false, sessionRestored: true  })),
    on(AuthActions.restoreSessionFailure,
      (s) => ({ ...s, user: null, token: null, loading: false, sessionRestored: true  })),

    on(AuthActions.loginWithGoogle, AuthActions.loginWithEmail,
      (s) => ({ ...s, loading: true, error: null })),
    on(AuthActions.loginWithGoogleSuccess,
      (s, { user, token }) => ({ ...s, user, token, loading: false })),
    on(AuthActions.loginWithEmailSuccess,
      (s, { user }) => ({ ...s, user, token: null, loading: false })),
    on(AuthActions.loginWithGoogleFailure, AuthActions.loginWithEmailFailure,
      (s, { error }) => ({ ...s, loading: false, error })),

    on(AuthActions.logoutSuccess,
      () => ({ ...initialState, sessionRestored: true  })),
  ),
});

import { Injectable, computed, inject, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { forkJoin } from 'rxjs';
import { ToastrService } from 'ngx-toastr';
import { environment } from '../../environments/environment';
import { AuthService } from '../core/auth/services/auth-service';
import { Product } from '../core/models/product.model';

export interface CartItem {
  productId: number;
  quantity: number;
  name: string;
  price: number;
  thumbnail: string;
  brand?: string;
  stock: number | string;
}

interface CartResponse {
  success: boolean;
  items: CartItem[];
}

interface WishlistResponse {
  success: boolean;
  productIds: number[];
  products: Product[];
}

@Injectable({ providedIn: 'root' })
export class UserListsService {
  private http = inject(HttpClient);
  private auth = inject(AuthService);
  private toastr = inject(ToastrService);
  private apiUrl = environment.apiUrl;

  cartItems = signal<CartItem[]>([]);
  wishlistIds = signal<number[]>([]);

  cartCount = computed(() =>
    this.cartItems().reduce((sum, item) => sum + item.quantity, 0)
  );

  wishlistCount = computed(() => this.wishlistIds().length);

  private get email(): string {
    const email = this.auth.user?.email?.trim().toLowerCase();
    if (!email) throw new Error('User not logged in');
    return email;
  }

  loadAll(): void {
    try {
      forkJoin({
        cart: this.http.get<CartResponse>(`${this.apiUrl}/cart/${this.email}`),
        wishlist: this.http.get<WishlistResponse>(`${this.apiUrl}/wishlist/${this.email}`),
      }).subscribe({
        next: ({ cart, wishlist }) => {
          this.cartItems.set(cart.items ?? []);
          this.wishlistIds.set(wishlist.productIds ?? []);
        },
        error: () => {
          this.cartItems.set([]);
          this.wishlistIds.set([]);
        },
      });
    } catch {
      this.cartItems.set([]);
      this.wishlistIds.set([]);
    }
  }

  isInWishlist(productId: number): boolean {
    return this.wishlistIds().includes(productId);
  }

  getCartQuantity(productId: number): number {
    return this.cartItems().find((item) => item.productId === productId)?.quantity ?? 0;
  }

  addToCart(product: Product, quantity = 1): void {
    this.http
      .post<CartResponse>(`${this.apiUrl}/cart/${this.email}`, {
        productId: product.id,
        quantity,
      })
      .subscribe({
        next: (res) => {
          this.cartItems.set(res.items ?? []);
          this.toastr.success(`${product.name} added to cart`);
        },
        error: () => this.toastr.error('Failed to add to cart'),
      });
  }

  updateCart(productId: number, quantity: number): void {
    this.http
      .patch<CartResponse>(`${this.apiUrl}/cart/${this.email}/${productId}`, { quantity })
      .subscribe({
        next: (res) => {
          this.cartItems.set(res.items ?? []);
          this.toastr.info('Cart updated');
        },
        error: () => this.toastr.error('Failed to update cart'),
      });
  }

  removeFromCart(productId: number): void {
    this.http.delete<CartResponse>(`${this.apiUrl}/cart/${this.email}/${productId}`).subscribe({
      next: (res) => {
        this.cartItems.set(res.items ?? []);
        this.toastr.warning('Item removed from cart');
      },
      error: () => this.toastr.error('Failed to remove item'),
    });
  }

  toggleWishlist(product: Product): void {
    if (this.isInWishlist(product.id)) {
      this.http
        .delete<WishlistResponse>(`${this.apiUrl}/wishlist/${this.email}/${product.id}`)
        .subscribe({
          next: (res) => {
            this.wishlistIds.set(res.productIds ?? []);
            this.toastr.warning(`${product.name} removed from wishlist`);
          },
          error: () => this.toastr.error('Failed to update wishlist'),
        });
      return;
    }

    this.http
      .post<WishlistResponse>(`${this.apiUrl}/wishlist/${this.email}`, {
        productId: product.id,
      })
      .subscribe({
        next: (res) => {
          this.wishlistIds.set(res.productIds ?? []);
          this.toastr.success(`${product.name} added to wishlist`);
        },
        error: () => this.toastr.error('Failed to update wishlist'),
      });
  }

  clear(): void {
    this.cartItems.set([]);
    this.wishlistIds.set([]);
  }
}

