  templateUrl: './login.html',
  styleUrl: './login.css',
})
export class Login implements AfterViewInit {
  @ViewChild('googleBtn', { static: false }) googleBtn!: ElementRef<HTMLDivElement>;

  private store      = inject(Store);
  private router     = inject(Router);
  private platformId = inject(PLATFORM_ID);

  form = { email: '', password: '' };

  // Observables — consumed with async pipe in template
  error$   = this.store.select(selectAuthError);
  loading$ = this.store.select(selectAuthLoading);

  constructor(@Inject(DOCUMENT) private document: Document) {}

  async ngAfterViewInit(): Promise<void> {
    if (!isPlatformBrowser(this.platformId) || !environment.googleClientId) return;
    try {
      await this.loadGoogleScript();
      this.renderGoogleButton();
    } catch (e) { console.error('GIS load failed', e); }
  }

  signin(form: NgForm): void {
    if (form.invalid) return;
    this.store.dispatch(AuthActions.loginWithEmail({
      email: this.form.email,
      password: this.form.password,
    }));
  }

  signup(): void {
    this.router.navigate(['/signup']);
  }

  private handleGoogle(credential: string): void {
    this.store.dispatch(AuthActions.loginWithGoogle({ credential }));
  }

  private loadGoogleScript(): Promise<void> {
    if (window.google?.accounts?.id) return Promise.resolve();
    const existing = this.document.getElementById('google-identity-script') as HTMLScriptElement | null;
    if (existing) {
      return new Promise((resolve, reject) => {
        existing.addEventListener('load', () => resolve(), { once: true });
        existing.addEventListener('error', () => reject(new Error('GIS load failed')), { once: true });
      });
    }
    return new Promise((resolve, reject) => {
      const script   = this.document.createElement('script');
      script.id      = 'google-identity-script';
      script.src     = 'https://accounts.google.com/gsi/client';
      script.async   = script.defer = true;
      script.onload  = () => resolve();
      script.onerror = () => reject(new Error('GIS load failed'));
      this.document.head.appendChild(script);
    });
  }

  private renderGoogleButton(): void {
    const target = this.googleBtn?.nativeElement;
    if (!target || !window.google?.accounts?.id) return;
    target.innerHTML = '';
    window.google.accounts.id.initialize({
      client_id: environment.googleClientId,
      callback: (res: { credential: string }) => this.handleGoogle(res.credential),
    });
    window.google.accounts.id.renderButton(target, {
      theme: 'outline', size: 'large', text: 'continue_with', width: 320,
    });
  }
}

import { Injectable, computed, inject, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { forkJoin } from 'rxjs';
import { ToastrService } from 'ngx-toastr';
import { environment } from '../../environments/environment';
import { AuthService } from '../core/auth/services/auth-service';
import { Product } from '../core/models/product.model';

export interface CartItem {
  productId: number;
  quantity: number;
  name: string;
  price: number;
  thumbnail: string;
  brand?: string;
  stock: number | string;
}

interface CartResponse {
  success: boolean;
  items: CartItem[];
}

interface WishlistResponse {
  success: boolean;
  productIds: number[];
  products: Product[];
}

@Injectable({ providedIn: 'root' })
export class UserListsService {
  private http = inject(HttpClient);
  private auth = inject(AuthService);
  private toastr = inject(ToastrService);
  private apiUrl = environment.apiUrl;

  cartItems = signal<CartItem[]>([]);
  wishlistIds = signal<number[]>([]);

  cartCount = computed(() =>
    this.cartItems().reduce((sum, item) => sum + item.quantity, 0)
  );

  wishlistCount = computed(() => this.wishlistIds().length);

  private get email(): string {
    const email = this.auth.user?.email?.trim().toLowerCase();
    if (!email) throw new Error('User not logged in');
    return email;
  }

  loadAll(): void {
    try {
      forkJoin({
        cart: this.http.get<CartResponse>(`${this.apiUrl}/cart/${this.email}`),
        wishlist: this.http.get<WishlistResponse>(`${this.apiUrl}/wishlist/${this.email}`),
      }).subscribe({
        next: ({ cart, wishlist }) => {
          this.cartItems.set(cart.items ?? []);
          this.wishlistIds.set(wishlist.productIds ?? []);
        },
        error: () => {
          this.cartItems.set([]);
          this.wishlistIds.set([]);
        },
      });
    } catch {
      this.cartItems.set([]);
      this.wishlistIds.set([]);
    }
  }

  isInWishlist(productId: number): boolean {
    return this.wishlistIds().includes(productId);
  }

  getCartQuantity(productId: number): number {
    return this.cartItems().find((item) => item.productId === productId)?.quantity ?? 0;
  }

  addToCart(product: Product, quantity = 1): void {
    this.http
      .post<CartResponse>(`${this.apiUrl}/cart/${this.email}`, {
        productId: product.id,
        quantity,
      })
      .subscribe({
        next: (res) => {
          this.cartItems.set(res.items ?? []);
          this.toastr.success(`${product.name} added to cart`);
        },
        error: () => this.toastr.error('Failed to add to cart'),
      });
  }

  updateCart(productId: number, quantity: number): void {
    this.http
      .patch<CartResponse>(`${this.apiUrl}/cart/${this.email}/${productId}`, { quantity })
      .subscribe({
        next: (res) => {
          this.cartItems.set(res.items ?? []);
          this.toastr.info('Cart updated');
        },
        error: () => this.toastr.error('Failed to update cart'),
      });
  }

  removeFromCart(productId: number): void {
    this.http.delete<CartResponse>(`${this.apiUrl}/cart/${this.email}/${productId}`).subscribe({
      next: (res) => {
        this.cartItems.set(res.items ?? []);
        this.toastr.warning('Item removed from cart');
      },
      error: () => this.toastr.error('Failed to remove item'),
    });
  }

  toggleWishlist(product: Product): void {
    if (this.isInWishlist(product.id)) {
      this.http
        .delete<WishlistResponse>(`${this.apiUrl}/wishlist/${this.email}/${product.id}`)
        .subscribe({
          next: (res) => {
            this.wishlistIds.set(res.productIds ?? []);
            this.toastr.warning(`${product.name} removed from wishlist`);
          },
          error: () => this.toastr.error('Failed to update wishlist'),
        });
      return;
    }

    this.http
      .post<WishlistResponse>(`${this.apiUrl}/wishlist/${this.email}`, {
        productId: product.id,
      })
      .subscribe({
        next: (res) => {
          this.wishlistIds.set(res.productIds ?? []);
          this.toastr.success(`${product.name} added to wishlist`);
        },
        error: () => this.toastr.error('Failed to update wishlist'),
      });
  }

  clear(): void {
    this.cartItems.set([]);
    this.wishlistIds.set([]);
  }
}

