import { inject, Injectable } from '@angular/core';
import { Router } from '@angular/router';
import { Actions, createEffect, ofType } from '@ngrx/effects';
import { catchError, from, map, of, switchMap, tap } from 'rxjs';
import { AuthActions } from './auth.actions';
import { AuthService, AppUser } from '../../core/auth/services/auth-service';
import { UserService } from '../../core/auth/services/user.service';   // ← CHANGED

@Injectable()
export class AuthEffects {
  private actions$    = inject(Actions);
  private authService = inject(AuthService);
  private userService = inject(UserService);   
  private router      = inject(Router);

  loginWithGoogle$ = createEffect(() =>
    this.actions$.pipe(
      ofType(AuthActions.loginWithGoogle),
      switchMap(({ credential }) =>
        from(this.authService.signInWithGoogle(credential)).pipe(
          map(() => {
            const { user, token } = this.authService;
            return AuthActions.loginWithGoogleSuccess({ user: user!, token: token! });
          }),
          catchError((err: Error) =>
            of(AuthActions.loginWithGoogleFailure({ error: err.message }))
          ),
        ),
      ),
    ),
  );

  loginWithEmail$ = createEffect(() =>
    this.actions$.pipe(
      ofType(AuthActions.loginWithEmail),
      switchMap(({ email, password }) =>
        this.userService.getUserByEmail(email).pipe(
          switchMap((res) => {
            const dbUser = res.user;

            if (dbUser.password !== password)
              return of(AuthActions.loginWithEmailFailure({ error: 'Incorrect password' }));

            const user: AppUser = {
              sub: dbUser.email,
              name: dbUser.name,
              email: dbUser.email,
              picture: '',
            };

            return from(this.authService.signInWithEmail(user)).pipe(
              map(() => AuthActions.loginWithEmailSuccess({ user }))
            );
          }),
          catchError((err) => {
            const message = err.status === 404
              ? 'User not found'
              : 'Login failed';
            return of(AuthActions.loginWithEmailFailure({ error: message }));
          }),
        ),
      ),
    ),
  );

  redirectAfterLogin$ = createEffect(
    () =>
      this.actions$.pipe(
        ofType(AuthActions.loginWithGoogleSuccess, AuthActions.loginWithEmailSuccess),
        tap(() => void this.router.navigate(['/home'])),
      ),
    { dispatch: false },
  );

  logout$ = createEffect(() =>
    this.actions$.pipe(
      ofType(AuthActions.logout),
      switchMap(() =>
        from(this.authService.logout()).pipe(
          map(() => AuthActions.logoutSuccess())
        ),
      ),
    ),
  );

  redirectAfterLogout$ = createEffect(
    () =>
      this.actions$.pipe(
        ofType(AuthActions.logoutSuccess),
        tap(() => void this.router.navigate(['/login'])),
      ),
    { dispatch: false },
  );
}

import { Inject, Injectable, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

export interface AppUser {
  sub:     string;
  name:    string;
  email:   string;
  picture: string;
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly tokenKey = 'auth_token';
  private readonly userKey  = 'auth_user';

  user:  AppUser | null = null;
  token: string | null  = null;

  constructor(@Inject(PLATFORM_ID) private platformId: object) {}

  async restoreSession(): Promise<void> {
    if (!isPlatformBrowser(this.platformId)) {
      console.log('[AuthService] Skipped — not browser (SSR)');
      return;
    }

    const storedToken   = sessionStorage.getItem(this.tokenKey);
    const storedUserRaw = sessionStorage.getItem(this.userKey);

    console.log('[AuthService] storedUserRaw:', storedUserRaw);
    console.log('[AuthService] storedToken:', storedToken);

    if (!storedUserRaw) { this.clear(); return; }

    try {
      this.user  = JSON.parse(storedUserRaw);
      this.token = storedToken ?? null;
    } catch { this.clear(); }
  }

  async signInWithGoogle(credential: string): Promise<void> {
    const payload = this.parseJwt(credential);
    this.token = credential;
    this.user  = {
      sub:     payload.sub,
      name:    payload.name,
      email:   payload.email,
      picture: payload.picture,
    };
    if (isPlatformBrowser(this.platformId)) {
      sessionStorage.setItem(this.tokenKey, credential);
      sessionStorage.setItem(this.userKey,  JSON.stringify(this.user));
    }
  }

  async signInWithEmail(user: AppUser): Promise<void> {
    this.token = null;
    this.user  = user;
    if (isPlatformBrowser(this.platformId)) {
      sessionStorage.removeItem(this.tokenKey);
      sessionStorage.setItem(this.userKey, JSON.stringify(user));
    }
  }

  async logout(): Promise<void> { this.clear(); }

  private clear(): void {
    this.token = null;
    this.user  = null;
    if (isPlatformBrowser(this.platformId)) {
      sessionStorage.removeItem(this.tokenKey);
      sessionStorage.removeItem(this.userKey);
    }
  }

  parseJwt(token: string): any {
    const parts  = token.split('.');
    if (parts.length < 2) throw new Error('Invalid JWT');
    const base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    const padded = base64 + '='.repeat((4 - (base64.length % 4)) % 4);
    return JSON.parse(atob(padded));
  }
}

import { Injectable } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class IndexedDbService {
  private dbName = 'eshopper-db';
  private storeName = 'users';

  openDB(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, 1);
      request.onupgradeneeded = () => {
        const db = request.result;
        if (!db.objectStoreNames.contains(this.storeName)) {
          db.createObjectStore(this.storeName, { keyPath: 'email' });
        }
      };
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async addUser(user: any): Promise<void> {
    const db = await this.openDB();

    return new Promise((resolve, reject) => {
      const tx = db.transaction(this.storeName, 'readwrite');
      const store = tx.objectStore(this.storeName);
      const req = store.add(user);
      req.onsuccess = () => resolve();
      req.onerror = () => reject('User already exists');
    });
  }

  async getUserByEmail(email: string): Promise<any> {
    const db = await this.openDB();

    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['users'], 'readonly');
      const store = transaction.objectStore('users');
      const request = store.get(email);
      console.log("request------------------------"+request)
      request.onsuccess = () => {
        resolve(request.result);
      };
      request.onerror = () => {
        reject('Failed to fetch user');
      };
    });
  }
}

