import { Injectable, inject } from '@angular/core';
import { Actions, createEffect, ofType } from '@ngrx/effects';
import { concatLatestFrom } from '@ngrx/operators';
import { Store } from '@ngrx/store';
import { catchError, debounceTime, map, of, switchMap } from 'rxjs';
import { ProductService } from '../../services/product.service';
import { ProductsActions } from './products.actions';
import {
  selectActiveCategory,
  selectPage,
  selectPageSize,
  selectSearchTerm,
  selectSortBy,
} from './products.selectors';

@Injectable()
export class ProductsEffects {
  private actions$ = inject(Actions);
  private store = inject(Store);
  private productService = inject(ProductService);

  searchChange$ = createEffect(() =>
    this.actions$.pipe(
      ofType(ProductsActions.setSearchTerm),
      debounceTime(300),
      map(() => ProductsActions.loadProducts())
    )
  );

  queryChange$ = createEffect(() =>
    this.actions$.pipe(
      ofType(
        ProductsActions.setCategory,
        ProductsActions.setSort,
        ProductsActions.setPage
      ),
      map(() => ProductsActions.loadProducts())
    )
  );

  loadCategories$ = createEffect(() =>
    this.actions$.pipe(
      ofType(ProductsActions.loadCategories),
      switchMap(() =>
        this.productService.getCategories().pipe(
          map((response) =>
            ProductsActions.loadCategoriesSuccess({
              categories: response.categories ?? [],
            })
          ),
          catchError(() =>
            of(
              ProductsActions.loadCategoriesFailure({
                error: 'Failed to load categories',
              })
            )
          )
        )
      )
    )
  );

  loadProducts$ = createEffect(() =>
    this.actions$.pipe(
      ofType(ProductsActions.loadProducts),
      concatLatestFrom(() => [
        this.store.select(selectSearchTerm),
        this.store.select(selectActiveCategory),
        this.store.select(selectSortBy),
        this.store.select(selectPage),
        this.store.select(selectPageSize),
      ]),
      switchMap(([, searchTerm, activeCategory, sortBy, page, pageSize]) =>
        this.productService
          .getProducts({
            search: searchTerm,
            category: activeCategory === 'All' ? undefined : activeCategory,
            sort: sortBy,
            page,
            pageSize,
          })
          .pipe(
            map((response) =>
              ProductsActions.loadProductsSuccess({
                products: response.products ?? [],
                total: response.total ?? 0,
                page: response.page ?? page,
                pageSize: response.pageSize ?? pageSize,
              })
            ),
            catchError(() =>
              of(
                ProductsActions.loadProductsFailure({
                  error: 'Failed to load products',
                })
              )
            )
          )
      )
    )
  );
}

import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../environments/environment';
import {
  CategoriesResponse,
  ProductResponse,
  ProductsResponse,
} from '../core/models/product.model';

export interface ProductQuery {
  search?: string;
  category?: string;
  sort?: 'price-asc' | 'price-desc';
  page?: number;
  pageSize?: number;
}

@Injectable({
  providedIn: 'root',
})
export class ProductService {
  private http = inject(HttpClient);
  private apiUrl = `${environment.apiUrl}/products`;

  getProducts(query: ProductQuery = {}): Observable<ProductsResponse> {
    let params = new HttpParams();

    if (query.search?.trim()) {
      params = params.set('search', query.search.trim());
    }

    if (query.category?.trim() && query.category !== 'All') {
      params = params.set('category', query.category);
    }

    if (query.sort) {
      params = params.set('sort', query.sort);
    }

    if (query.page != null) {
      params = params.set('page', query.page);
    }

    if (query.pageSize != null) {
      params = params.set('pageSize', query.pageSize);
    }

    return this.http.get<ProductsResponse>(this.apiUrl, { params });
  }

  getCategories(): Observable<CategoriesResponse> {
    return this.http.get<CategoriesResponse>(`${this.apiUrl}/categories`);
  }

  getProductById(id: number): Observable<ProductResponse> {
    return this.http.get<ProductResponse>(`${this.apiUrl}/${id}`);
  }
}

